import * as React from 'react'
import {Link, HeadFC, PageProps} from 'gatsby'
import {LifeShooter} from '../components/LifeShooter'

// <marquee> is gloriously deprecated and has no React JSX typing — render it via
// createElement so the 2003 dream survives a strict typecheck.
const Marquee = ({children}: {children: React.ReactNode}) =>
  React.createElement('marquee', null, children)

const NotFoundPage: React.FC<PageProps> = () => {
  return (
    <main className="notfound mx-auto max-w-xl md:max-w-xl lg:max-w-5xl py-12 px-12 mono">
      <header className="nf-head">
        <img
          className="bear"
          src="/beartracker.webp"
          alt="A pixelated polar bear and its cub, tracking"
        />
        <div>
          <h1 className="yellow title text-3xl blink mb-3">404 · PAGE NOT FOUND</h1>
          <p className="text-sm mb-3">
            BearTracker™ v0.4 sniffed every URL on this server and came back empty-pawed.
            <br />
            The page you seek does not exist (or has migrated south for the winter).
          </p>
        </div>
      </header>

      <section className="nf-game">
        <p className="text-sm mb-1">while you’re stuck here, shoot some UFOs and watch them burn:</p>
        <p className="text-xs mb-3">↑ ↓ ← → or drag to fly</p>
        <LifeShooter />
      </section>

      <p className="text-sm mb-3">
        <Link to="/" className="yellow">
          « back to safety (the CV) »
        </Link>
      </p>

      <Marquee>
        ⚠ 404 ⚠ you have wandered off the trail · BearTracker™ could not locate this page · turn
        back before nightfall · ⚠
      </Marquee>
    </main>
  )
}

export default NotFoundPage

export const Head: HeadFC = () => <title>404 · lost in the woods</title>
