// Render colours for the LifeShooter 404 game, extracted as pure functions so the
// prefers-reduced-motion invariant (no >3 Hz colour flashing — WCAG 2.3.1) is
// unit-testable without a DOM/canvas harness. See lifeShooterColors.test.ts.
//
// The game's only high-frequency flashes are the fire layer and the swarm banner.
// When reduced motion is requested they collapse to a single steady colour so the
// canvas no longer strobes; gameplay position motion is unaffected (handled in the
// component). Run via `npm run test:unit` (node --test).

// Fire layer: warm flicker alternating per cell+tick (≈15 Hz over large areas),
// or a single steady warm colour under reduced motion.
export const fireColor = (x: number, y: number, tick: number, reduce: boolean): string =>
  reduce ? '#ff5a00' : (x + y + tick) & 1 ? '#ffcc00' : '#ff5a00'

// "★ 404 · THE SWARM ★" banner: red/yellow flash every 2 ticks (≈7.7 Hz), or a
// steady red under reduced motion.
export const bannerColor = (tick: number, reduce: boolean): string =>
  reduce ? '#ff3b2f' : tick & 2 ? '#ff3b2f' : '#ffcc00'
